mapper.select:
select YYYYMM, SEL_CODE, SITE as SITE_ORG, CASE WHEN SITE='HQ' then '본사' WHEN SITE='VN' then 'VINA' end as SITE, MODEL, MODEL_TYPE, STOCK, BOH, [INPUT], [OUT], EOH, INPUT_ETC, INPUT_MOVING, INPUT_PROD, OUT_SHEET, OUT_RETURN, OUT_INVOICE, OUT_ETC, OUT_MOVING from DOI_STOCK where 1=1
and yyyymm = #{yyyymm}
and site = #{site}
order BY MODEL, MODEL_TYPE;

DROP TABLE IF EXISTS #TempTable1;

CREATE TABLE #TempTable1 (
	YYYYMM varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	SEL_CODE varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	SITE varchar(4) COLLATE Korean_Wansung_CI_AS NOT NULL,
	MODEL nvarchar(50) COLLATE Korean_Wansung_CI_AS NOT NULL,
	MODEL_TYPE nvarchar(50) COLLATE Korean_Wansung_CI_AS NOT NULL,
	STOCK nvarchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	BOH int NULL,
	[INPUT] int NULL,
	[OUT] int NULL,
	EOH int NULL,
	INPUT_ETC int NULL,
	INPUT_MOVING int NULL,
	INPUT_PROD int NULL,
	OUT_SHEET int NULL,
	OUT_RETURN int NULL,
	OUT_INVOICE int NULL,
	OUT_ETC int NULL,
	OUT_MOVING int NULL
);

INSERT INTO #TempTable1
(
YYYYMM,SEL_CODE,SITE,MODEL,MODEL_TYPE,STOCK,BOH,[INPUT],[OUT],EOH,INPUT_ETC,INPUT_MOVING,INPUT_PROD,OUT_SHEET,OUT_RETURN,OUT_INVOICE,OUT_ETC,OUT_MOVING
)
VALUES

	(
	#{item.field2}
	, #{item.field3}
	, #{item.field4}
	, #{item.field5}
	, #{item.field6}
	, #{item.field7}
	, #{item.field8}
	, #{item.field9}
	, #{item.field10}
	, #{item.field11}
	, #{item.field12}
	, #{item.field13}
	, #{item.field14}
	, #{item.field15}
	, #{item.field16}
	, #{item.field17}
	, #{item.field18}
	, #{item.field19}
	)
;

SELECT * FROM #TempTable1 a
WHERE EXISTS (
	SELECT 1
	FROM DOI_STOCK b
	WHERE 1=1
	AND b.YYYYMM = a.YYYYMM
	AND b.SEL_CODE = a.SEL_CODE
	AND b.SITE = a.SITE
	AND b.MODEL = a.MODEL
	AND b.MODEL_TYPE = a.MODEL_TYPE
	AND b.STOCK = a.STOCK
);

