,INPUT_PROD = #{inputProd}
,OUT_SHEET = #{outSheet}
,OUT_RETURN = #{outReturn}
,OUT_INVOICE = #{outInvoice}
,OUT_ETC = #{outEtc}
,OUT_MOVING = #{outMoving}
WHERE 1=1
and yyyymm = #{yyyymm}
and sel_code = #{selCode}
and site = #{siteOrg}
